contentBefore:
:root {
  --bg: #1b1b1f;
  --bg-side: #161619;
  --bg-elev: #242429;
  --bg-input: #2a2a31;
  --border: #34343c;
  --text: #e7e7ec;
  --text-dim: #9a9aa4;
  --text-faint: #6c6c76;
  --accent: #e8b339;
  --accent-dim: #6b5320;
  --accent-fg: #1b1b1f;
  --ok: #4ec27a;
  --err: #e2614c;
  --run: #e8b339;
  --code-bg: #131316;
}
/* 淡色主题:在 <html data-theme="light"> 生效。颜色对齐 macOS System Light。 */
[data-theme="light"] {
  --bg: #f6f6f9;
  --bg-side: #ececf0;
  --bg-elev: #ffffff;
  --bg-input: #ffffff;
  --border: #d9d9e0;
  --text: #1b1b1f;
  --text-dim: #55555f;
  --text-faint: #8a8a93;
  --accent: #b88200;
  --accent-dim: #d9a840;
  --accent-fg: #ffffff;
  --code-bg: #f0f0f4;
}
#head-status { color: var(--text-dim); font-size: 12px; margin-left: 6px; }
.send.stop { background: #9c3a3a; border-color: #9c3a3a; }
#turns, #q-out { user-select: text; cursor: text; }
* { box-sizing: border-box; }
html, body { height: 100%; margin: 0; }

/* Windows 默认滚动条粗灰色方块丑。全局自定义:细、半透明、悬浮加深,所有窗口统一。
   webview 内的网页自带滚动条不动(那是页面作者决定的)。 */
::-webkit-scrollbar { width: 10px; height: 10px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 5px; border: 2px solid transparent; background-clip: content-box; }
::-webkit-scrollbar-thumb:hover { background: var(--text-faint); background-clip: content-box; border: 2px solid transparent; }
::-webkit-scrollbar-corner { background: transparent; }
body {
  background: var(--bg);
  color: var(--text);
  font: 13px/1.55 -apple-system, "Segoe UI", system-ui, "PingFang SC", "Microsoft YaHei", sans-serif;
  -webkit-font-smoothing: antialiased;
  user-select: none;
}
button {
  font: inherit; color: var(--text); background: var(--bg-elev); border: 1px solid var(--border);
  border-radius: 6px; padding: 6px 12px; cursor: pointer;
}
button:hover { border-color: var(--accent-dim); }
button.primary { background: var(--accent); color: #1b1b1f; border-color: var(--accent); font-weight: 600; }
button.primary:hover { filter: brightness(1.08); }
button.ghost { background: transparent; border-color: transparent; color: var(--text-dim); }
button.ghost:hover { color: var(--text); background: var(--bg-elev); }
input, textarea, select {
  font: inherit; color: var(--text); background: var(--bg-input); border: 1px solid var(--border);
  border-radius: 6px; padding: 7px 9px; width: 100%;
}
input:focus, textarea:focus, select:focus { outline: none; border-color: var(--accent-dim); }
a { color: var(--accent); }

#app { display: flex; height: 100vh; }

/* sidebar */
#sidebar {
  width: 256px; flex-shrink: 0; background: var(--bg-side); border-right: 1px solid var(--border);
  display: flex; flex-direction: column;
}
.sb-head { padding: 12px; display: flex; align-items: center; gap: 8px; }
.sb-head .brand { font-weight: 700; font-size: 14px; flex: 1; }
.sb-head .brand .spark { color: var(--accent); }
.sb-actions { display: flex; gap: 2px; align-items: center; }
/* 高频按钮(＋ 📂 ⚙)+ 更多菜单(⋯):4 个按钮在 256px sidebar 里宽敞不挤。
   低频功能(仪表盘/文件/Arena/记忆/快照)收纳进 ⋯ 下拉,需要时点开。 */
.sb-actions .ghost { padding: 5px 6px; font-size: 13px; }

/* 下拉菜单 ⋯ — 点击展开,点外部收起 */
.sb-more-wrap { position: relative; }
.sb-more-menu {
  display: none; position: absolute; top: calc(100% + 4px); right: 0; z-index: 100;
  background: var(--bg-elev); border: 1px solid var(--border); border-radius: 8px;
  padding: 4px; min-width: 160px; box-shadow: 0 6px 20px rgba(0,0,0,.4);
}
.sb-more-menu.open { display: block; }
.sb-more-item {
  display: flex; align-items: center; gap: 8px; width: 100%;
  background: transparent; border: none; border-radius: 5px;
  padding: 7px 10px; font: inherit; color: var(--text); cursor: pointer; text-align: left;
}
.sb-more-item:hover { background: var(--bg-input); }
.sb-mi-ico { font-size: 13px; width: 18px; text-align: center; flex-shrink: 0; }
.sb-mi-label { font-size: 12px; }
.sb-more-sep { height: 1px; background: var(--border); margin: 4px 6px; }
#conv-list { list-style: none; margin: 0; padding: 0 6px; overflow-y: auto; flex: 1; }
/* ponytail: 用 > 限定直接子项,避免 .sb-proj-tasks 里的嵌套 li 继承 flex-direction:column。 */
#conv-list > li {
  padding: 8px 10px; border-radius: 7px; cursor: pointer; margin-bottom: 2px;
  display: flex; flex-direction: column; gap: 2px;
}
#conv-list > li:hover { background: var(--bg-elev); }
#conv-list > li.active { background: var(--bg-elev); }
#conv-list > li.active .title { color: var(--accent); }
#conv-list > li { position: relative; }
#conv-list > li .conv-actions { position: absolute; right: 6px; top: 50%; transform: translateY(-50%); display: none; gap: 2px; background: var(--bg-elev); padding: 2px; border-radius: 6px; }
#conv-list > li:hover .conv-actions { display: inline-flex; }
.ca-btn { background: transparent; border: none; color: var(--text-dim); padding: 2px 5px; font-size: 12px; line-height: 1; cursor: pointer; }
.ca-btn:hover { color: var(--text); }
.ca-btn[data-act="delete"]:hover { color: var(--err); }
#conv-list .title { font-size: 13px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
#conv-list .meta { font-size: 11px; color: var(--text-faint); display: flex; gap: 8px; align-items: center; }
.dot { width: 8px; height: 8px; border-radius: 50%; display: inline-block; flex-shrink: 0; }
.dot.ready { background: var(--text-faint); }
.dot.running { background: var(--run); box-shadow: 0 0 6px var(--run); animation: pulse 1.1s infinite; }
.dot.error { background: var(--err); }
@keyframes pulse { 0%,100%{opacity:1} 50%{opacity:.35} }
.sb-foot { padding: 8px 12px; border-top: 1px solid var(--border); font-size: 11px; color: var(--text-faint); display: flex; align-items: center; gap: 6px; }
.sb-foot-info { white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.sb-foot-spacer { flex: 1; }
.sb-mode { padding: 2px 7px; font-size: 13px; line-height: 1; }
.sb-mode:hover { color: var(--text); }

/* 顶栏按钮 active 态:📂 / ⚙ 当前所在视图时高亮,让用户知道点回去会切走。 */
#sidebar .sb-actions .ghost.active { color: var(--accent); background: var(--bg-elev); }

/* flat 模式下顶层 li 用原来的卡片样式(分组模式的子项另写) */
/* 同时显示 cwd basename(flat 模式无项目头,要标项目归属);grouped 模式 .sb-task-cwd 隐藏。 */
#conv-list > li:not(.sb-proj) {
  padding: 8px 10px; border-radius: 7px; cursor: pointer; margin-bottom: 2px;
  display: flex; align-items: center; gap: 7px; position: relative;
}
#conv-list > li:not(.sb-proj):hover { background: var(--bg-elev); }
#conv-list > li:not(.sb-proj).active { background: var(--bg-elev); }
#conv-list > li:not(.sb-proj).active .title { color: var(--accent); }
#conv-list > li:not(.sb-proj) .title-wrap { flex: 1; min-width: 0; display: flex; flex-direction: column; gap: 1px; }
#conv-list > li:not(.sb-proj) .title { font-size: 13px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
#conv-list > li:not(.sb-proj) .sb-task-cwd { font-size: 10.5px; color: var(--text-faint); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
#conv-list > li:not(.sb-proj) .conv-actions { position: absolute; right: 6px; top: 50%; transform: translateY(-50%); display: none; gap: 2px; background: var(--bg-elev); padding: 2px; border-radius: 6px; }
#conv-list > li:not(.sb-proj):hover .conv-actions { display: inline-flex; }
/* grouped 模式:任务条目不显示 cwd(已有项目头),title 直接横排。 */
.sb-proj-tasks li .title-wrap { flex: 1; min-width: 0; display: flex; align-items: center; gap: 7px; }
.sb-proj-tasks li .sb-task-cwd { display: none; }

/* main */
#main { flex: 1; display: flex; flex-direction: column; min-width: 0; }
.view { flex: 1; display: none; flex-direction: column; min-height: 0; }
.view.active { display: flex; }

/* sidebar 项目分组(按 cwd 聚合):.sb-proj 是单条 li,含 head + 嵌套 ul。 */
#conv-list li.sb-proj { padding: 0; cursor: default; }
#conv-list li.sb-proj.active { background: transparent; }
.sb-proj-head {
  display: flex; align-items: center; gap: 5px;
  padding: 6px 10px 4px; cursor: default; user-select: none;
  font-size: 11px; color: var(--text-dim);
}
.sb-proj-head:hover { color: var(--text); }
.sb-proj-head:hover .sb-pacts { display: inline-flex; }
.sb-chevron { display: inline-block; width: 9px; font-size: 8px; color: var(--text-faint); text-align: center; }
.sb-pico { font-size: 11px; }
.sb-pname { flex: 1; font-weight: 600; font-size: 12px; color: var(--text); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.sb-pcount { font-size: 10.5px; color: var(--text-faint); background: var(--bg-elev); padding: 1px 7px; border-radius: 9px; }
.sb-pacts { display: none; }
.sb-proj-tasks { list-style: none; margin: 0; padding: 0 0 4px; }
.sb-proj-tasks li {
  padding: 6px 10px 6px 28px; border-radius: 7px; cursor: pointer; margin: 0 4px 1px;
  display: flex; align-items: center; gap: 7px; position: relative;
}
.sb-proj-tasks li:hover { background: var(--bg-elev); }
.sb-proj-tasks li.active { background: var(--bg-elev); }
.sb-proj-tasks li.active .title { color: var(--accent); }
.sb-proj-tasks li .title { font-size: 12.5px; flex: 1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.sb-proj-tasks li .conv-actions { position: absolute; right: 6px; top: 50%; transform: translateY(-50%); display: none; gap: 2px; background: var(--bg-elev); padding: 2px; border-radius: 6px; }
.sb-proj-tasks li:hover .conv-actions { display: inline-flex; }

/* chat header — 拆成标题行 + 配置行,避免一行塞太多控件互相遮挡 */
.chat-head { padding: 8px 16px; border-bottom: 1px solid var(--border); display: flex; flex-direction: column; gap: 6px; }
.ch-row { display: flex; align-items: center; gap: 8px; min-width: 0; }
.ch-tabs { display: inline-flex; gap: 2px; margin-left: 8px; padding-left: 8px; border-left: 1px solid var(--border); }
.cht { font: inherit; font-size: 12px; padding: 4px 10px; background: transparent; border: 1px solid transparent; border-radius: 6px; color: var(--text-dim); cursor: default; }
.cht:hover { color: var(--text); background: var(--bg-elev); }
.cht.active { color: var(--text); background: var(--bg-elev); border-color: var(--border); }

/* chat-content 包 #turns + #input;chat-files-pane 内联文件浏览器。两者互斥(由 tab 切换)。 */
.chat-content { flex: 1; display: flex; flex-direction: column; min-height: 0; }
.chat-content[hidden] { display: none; }
.chat-files-pane { flex: 1; display: flex; flex-direction: column; min-height: 0; }
.chat-files-pane[hidden] { display: none; }
.chat-git-pane { flex: 1; display: flex; flex-direction: column; min-height: 0; }
.chat-git-pane[hidden] { display: none; }
.chat-rules-pane { flex: 1; display: flex; flex-direction: column; min-height: 0; }
.chat-rules-pane[hidden] { display: none; }

/* Rules tab:头(标题 + 状态 + 保存)+ 全屏 textarea 编辑器 */
.rules-head { display: flex; align-items: center; gap: 10px; padding: 8px 12px; border-bottom: 1px solid var(--border); }
.rules-title { font-size: 12.5px; color: var(--text-dim); }
.rules-spacer { flex: 1; }
.rules-status { font-size: 11.5px; color: var(--text-faint); }
.rules-editor-host { flex: 1; min-height: 0; overflow: hidden; }
.rules-editor-host .ce-wrap.ce-full { border-radius: 0; }

/* Git tab:头 + 两栏(左 changes,右 history/diff) */
.git-head { display: flex; align-items: center; gap: 8px; padding: 8px 12px; border-bottom: 1px solid var(--border); }
.git-branch { font-size: 12.5px; color: var(--text-dim); font-family: ui-monospace, SFMono-Regular, Menlo, monospace; }
.git-spacer { flex: 1; }
.git-body { flex: 1; display: grid; grid-template-columns: 38% 62%; min-height: 0; }
.git-col { display: flex; flex-direction: column; min-height: 0; border-right: 1px solid var(--border); }
.git-col:last-child { border-right: none; }
.gb-title { font-size: 11px; color: var(--text-dim); padding: 8px 12px; border-bottom: 1px solid var(--border); background: var(--bg-side); display: flex; align-items: center; gap: 8px; }
.gb-list { flex: 1; overflow: auto; padding: 4px 0; }
.git-empty { color: var(--text-faint); font-size: 12px; padding: 14px 12px; }

.gc-row { display: grid; grid-template-columns: 28px 60px 1fr; gap: 6px; padding: 4px 12px; cursor: pointer; font-size: 12.5px; align-items: center; }
.gc-row:hover { background: var(--bg-elev); }
.gc-code { font-family: ui-monospace, SFMono-Regular, Menlo, monospace; font-weight: 600; text-align: center; padding: 1px 4px; border-radius: 3px; font-size: 11px; }
.gc-code.M { background: rgba(232,179,57,.18); color: #e8b339; }
.gc-code.A { background: rgba(80,200,120,.18); color: #50c878; }
.gc-code.D { background: rgba(220,80,80,.18); color: #dc5050; }
.gc-code.R { background: rgba(120,160,220,.18); color: #78a0dc; }
.gc-code.U { background: rgba(150,150,160,.18); color: var(--text-dim); }
.gc-label { font-size: 11px; color: var(--text-dim); }
.gc-path { color: var(--text); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; font-family: ui-monospace, SFMono-Regular, Menlo, monospace; font-size: 11.5px; }

.gl-row { display: grid; grid-template-columns: 64px 70px 1fr 80px; gap: 8px; padding: 6px 12px; cursor: pointer; font-size: 12px; align-items: baseline; }
.gl-row:hover { background: var(--bg-elev); }
.gl-hash { font-family: ui-monospace, SFMono-Regular, Menlo, monospace; color: var(--accent); font-size: 11px; }
.gl-date { color: var(--text-faint); font-size: 11px; }
.gl-subject { color: var(--text); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.gl-author { color: var(--text-dim); font-size: 11px; text-align: right; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

.git-back { font: inherit; font-size: 11.5px; padding: 2px 8px; }
.git-diff-title { color: var(--text-dim); font-family: ui-monospace, SFMono-Regular, Menlo, monospace; font-size: 11.5px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.git-diff { margin: 0; padding: 10px 12px; font-family: ui-monospace, SFMono-Regular, Menlo, monospace; font-size: 11.5px; line-height: 1.55; color: var(--text); white-space: pre-wrap; word-break: break-word; user-select: text; }
/* ponytail: diff 高亮只到 +/-/@@ 行级(行首字符匹配),不到 token 粒度;够清楚就行。 */
.git-diff .d-add { color: #50c878; }
.git-diff .d-del { color: #dc5050; }
.git-diff .d-hunk { color: var(--text-faint); }
.git-diff .d-meta { color: var(--text-dim); display: block; }

/* 文件 diff 左右对比表(修改前 / 修改后)。表行同高天然对齐,无需 JS 同步滚动。 */
.git-ss { width: 100%; border-collapse: collapse; font-family: ui-monospace, SFMono-Regular, Menlo, monospace; font-size: 11.5px; }
.git-ss th { font-size: 10.5px; color: var(--text-dim); text-align: left; padding: 6px 8px; border-bottom: 1px solid var(--border); background: var(--bg-side); font-weight: 500; }
.git-ss th.ss-num { width: 42px; }
.git-ss td { padding: 0 8px; vertical-align: top; line-height: 1.55; }
.git-ss td.ss-num { width: 42px; color: var(--text-faint); text-align: right; user-select: none; white-space: nowrap; }
.git-ss td.ss-txt { white-space: pre-wrap; word-break: break-all; }
.git-ss tr.ss-hunk td { color: var(--text-faint); padding: 6px 8px; }
.git-ss tr.ss-del td:nth-child(2) { background: rgba(220,80,80,.14); }
.git-ss tr.ss-add td:nth-child(4) { background: rgba(80,200,120,.14); }
.git-ss tr.ss-mod td:nth-child(2) { background: rgba(220,80,80,.10); }
.git-ss tr.ss-mod td:nth-child(4) { background: rgba(80,200,120,.10); }
.ch-title .t { font-weight: 600; flex: 1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; min-width: 0; }
.ch-title .stat,
.ch-title .status { font-size: 11px; color: var(--text-dim); white-space: nowrap; }
.ch-config .engine { width: auto; flex: 0 0 auto; font-size: 12px; padding: 4px 8px; }
.ch-config .model { flex: 0 1 170px; min-width: 110px; font-size: 11px; padding: 4px 8px; font-family: ui-monospace, "Cascadia Code", monospace; color: var(--text-dim); }
.ch-config .cwd { flex: 1 1 220px; min-width: 120px; font-size: 11px; color: var(--text-faint); font-family: ui-monospace, "Cascadia Code", monospace; padding: 4px 8px; }
.ch-config .cwd-pick { flex: 0 0 auto; padding: 4px 8px; }
.stat { font-size: 11px; color: var(--text-dim); }

/* turns */
#turns { flex: 1; overflow-y: auto; padding: 18px 0; }
.turn { padding: 4px 20px 16px; display: flex; flex-direction: column; gap: 12px; }
.msg { display: flex; gap: 8px; align-items: flex-start; }
.msg.user { flex-direction: row-reverse; } /* 头像在右 */
.avatar { width: 28px; height: 28px; border-radius: 50%; flex-shrink: 0; display: flex; align-items: center; justify-content: center; font-size: 15px; }
.msg.user .avatar { background: var(--accent-dim); }
.msg.ai .avatar { background: var(--bg-elev); border: 1px solid var(--border); }
.msg .bubble { max-width: 78%; padding: 8px 12px; border-radius: 12px; white-space: pre-wrap; word-break: break-word; background: var(--bg-elev); border: 1px solid var(--border); }
.msg.user .bubble { border-top-right-radius: 4px; }
.msg .ai-body { max-width: 78%; min-width: 0; }
.msg .ai-body .answer { margin-top: 0; }
.msg .ai-body .steps { margin: 0 0 8px; }
.answer { margin-top: 12px; user-select: text; }
.answer.streaming { white-space: pre-wrap; font-family: ui-monospace, "Cascadia Code", monospace; font-size: 12px; color: var(--text-dim); }
.typing { display: inline-flex; gap: 5px; padding: 6px 2px; }
.typing i { width: 6px; height: 6px; border-radius: 50%; background: var(--text-dim); animation: typing-blink 1.3s infinite ease-in-out; }
.typing i:nth-child(2) { animation-delay: .2s; }
.typing i:nth-child(3) { animation-delay: .4s; }
@keyframes typing-blink { 0%, 60%, 100% { opacity: .25; transform: translateY(0); } 30% { opacity: 1; transform: translateY(-3px); } }
.answer p { margin: 0 0 8px; }
.answer h1,.answer h2,.answer h3 { margin: 14px 0 6px; }
.answer h1 { font-size: 17px; } .answer h2 { font-size: 15px; } .answer h3 { font-size: 14px; }
.answer ul,.answer ol { margin: 0 0 8px; padding-left: 22px; }
.answer blockquote { margin: 0 0 8px; padding-left: 12px; border-left: 3px solid var(--border); color: var(--text-dim); }
.answer .ic, .answer .code { font-family: ui-monospace, "Cascadia Code", monospace; background: var(--code-bg); border-radius: 4px; }
.answer .ic { padding: 1px 5px; font-size: 12px; }
.answer .code { display: block; padding: 10px 12px; overflow-x: auto; white-space: pre; user-select: text; font-size: 12px; }
.steps { margin: 8px 0; }
.step { border-left: 2px solid var(--accent-dim); padding: 6px 10px; margin-bottom: 6px; background: var(--bg-side); border-radius: 0 6px 6px 0; font-size: 12px; }
.step .name { color: var(--accent); font-weight: 600; }
.step details summary { cursor: pointer; color: var(--text-dim); }
.step pre { margin: 6px 0 0; white-space: pre-wrap; word-break: break-word; font-family: ui-monospace, "Cascadia Code", monospace; font-size: 11px; color: var(--text-dim); user-select: text; }
.turn .err { color: var(--err); }

/* input */
#input { border-top: 1px solid var(--border); padding: 10px 16px 12px; display: flex; flex-direction: column; gap: 8px; position: relative; }
#input textarea { resize: none; width: 100%; min-height: 60px; max-height: 180px; }
.composer-bar { display: flex; align-items: center; gap: 6px; flex-wrap: wrap; }
.composer-bar .tool { background: transparent; border: 1px solid var(--border); color: var(--text-dim); padding: 5px 10px; border-radius: 16px; font-size: 12px; display: inline-flex; align-items: center; gap: 5px; }
.composer-bar .tool:hover { color: var(--text); border-color: var(--accent-dim); }
.composer-bar .tool .lbl { font-size: 11px; }
.composer-bar .model-pill { flex: 0 0 auto; min-width: 120px; max-width: 180px; font-size: 11px; padding: 5px 10px; border-radius: 16px; font-family: ui-monospace, "Cascadia Code", monospace; color: var(--text-dim); }
.composer-bar .bar-spacer { flex: 1 1 auto; }
/* 语音输入按钮:listening 状态红点闪烁 */
.composer-bar .tool.listening { color: var(--danger); border-color: var(--danger); animation: mic-pulse 1.2s ease-in-out infinite; }
.composer-bar .tool.disabled { opacity: 0.4; cursor: not-allowed; }
@keyframes mic-pulse { 0%, 100% { box-shadow: 0 0 0 0 rgba(220, 50, 50, 0.4); } 50% { box-shadow: 0 0 0 4px rgba(220, 50, 50, 0); } }
/* AI 回复底部的小操作条(目前只有 🔊 朗读)。ponytail: 直接复用 .ghost,加点边距 */
.ai-actions { margin-top: 6px; display: flex; gap: 6px; opacity: 0.7; }
.ai-actions .ghost { padding: 2px 8px; font-size: 12px; }
.ai-body:hover .ai-actions { opacity: 1; }
.composer-bar .send { flex-shrink: 0; }
.attach-row { flex: 0 0 100%; display: flex; flex-wrap: wrap; gap: 6px; }
.attach-row:empty { display: none; }
.chip { font-size: 11px; background: var(--bg-elev); border: 1px solid var(--border); border-radius: 12px; padding: 3px 6px 3px 10px; display: inline-flex; align-items: center; gap: 6px; max-width: 240px; }
.chip > span:first-child { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.chip-x { cursor: pointer; color: var(--text-dim); padding: 0 5px; border-radius: 50%; }
.chip-x:hover { color: var(--err); }
#input.drag { outline: 2px dashed var(--accent); outline-offset: -4px; background: rgba(232,179,57,0.06); }

/* slash skill menu — floats above the composer while the user types /<name> */
.slash-menu {
  position: absolute;
  left: 16px; right: 16px;
  bottom: 100%;
  margin-bottom: 6px;
  background: var(--bg-elev);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: 0 -8px 24px rgba(0,0,0,.4);
  max-height: 280px;
  overflow-y: auto;
  z-index: 40;
  padding: 4px;
}
.slash-item { padding: 7px 10px; border-radius: 7px; cursor: pointer; display: flex; flex-direction: column; gap: 1px; }
.slash-item.active { background: var(--bg-input); }
.slash-item .slash-name { color: var(--text); font-size: 13px; font-weight: 600; }
.slash-item .slash-name .slash-tag { color: var(--accent); font-weight: 400; font-size: 11px; margin-left: 6px; }
.slash-item .slash-desc { color: var(--text-dim); font-size: 12px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.slash-empty { padding: 10px 12px; color: var(--text-faint); font-size: 12px; }

/* MCP 服务面板(mcp 按钮弹出) */
.mcp-menu { position: absolute; left: 16px; bottom: 100%; margin-bottom: 6px; width: 320px; max-width: calc(100vw - 48px); background: var(--bg-elev); border: 1px solid var(--border); border-radius: 10px; box-shadow: 0 -8px 24px rgba(0,0,0,.4); max-height: 340px; overflow-y: auto; z-index: 41; padding: 8px; }
.mcp-srv { padding: 7px 4px; border-bottom: 1px solid var(--border); }
.mcp-srv:last-child { border-bottom: none; }
.mcp-srv-name { font-size: 12px; font-weight: 600; }
.mcp-srv-name .mcp-src { font-size: 10px; color: var(--accent); font-weight: 400; margin-left: 6px; text-transform: uppercase; }
.mcp-tools { display: flex; flex-wrap: wrap; gap: 4px; margin-top: 5px; }
.mcp-tool { font-size: 10px; font-family: ui-monospace, "Cascadia Code", monospace; background: var(--bg-input); border: 1px solid var(--border); border-radius: 4px; padding: 1px 5px; color: var(--text-dim); }
.mcp-empty { padding: 10px 6px; font-size: 12px; color: var(--text-faint); line-height: 1.6; }

.empty { display: flex; flex-direction: column; align-items: center; justify-content: center; height: 100%; color: var(--text-faint); gap: 6px; }

/* settings */
#settings { padding: 24px; overflow-y: auto; }
#settings .card { max-width: 560px; }
#settings h2 { margin: 0 0 4px; font-size: 18px; }
#settings .sub { color: var(--text-dim); margin-bottom: 18px; }
.field { margin-bottom: 14px; }
.field label { display: block; font-size: 12px; color: var(--text-dim); margin-bottom: 4px; }
.field .row { display: flex; gap: 8px; }
.field .row > * { flex: 1; }
/* 设置页分组:每个 s-section 是一组同类字段(接口/行为/价格/界面),顶部 h3 标题。 */
.s-section { margin-top: 22px; padding-top: 14px; border-top: 1px solid var(--border); }
.s-section:first-of-type { border-top: none; margin-top: 14px; padding-top: 0; }
.s-section h3 { margin: 0 0 12px 0; font-size: 12px; font-weight: 600; color: var(--accent); text-transform: uppercase; letter-spacing: 0.5px; }
.test-msg { font-size: 12px; margin-top: 6px; }
.test-msg.ok { color: var(--ok); } .test-msg.bad { color: var(--err); }
/* plugin list in settings */
.s-plugin-list { width: 100%; display: flex; flex-direction: column; gap: 6px; }
.s-plugin-row { padding: 8px 10px; border: 1px solid var(--border); border-radius: 6px; background: var(--bg-elev, rgba(255,255,255,0.02)); }
.s-plugin-name { font-size: 13px; font-weight: 600; }
.s-plugin-ver { font-size: 11px; color: var(--muted, var(--text-dim)); font-weight: 400; margin-left: 6px; }
.s-plugin-meta { font-size: 11px; color: var(--muted, var(--text-dim)); margin-top: 2px; }
.s-plugin-err { display: inline-block; margin-top: 4px; font-size: 11px; color: var(--err, var(--danger)); }
.s-plugin-empty { font-size: 12px; color: var(--muted, var(--text-dim)); padding: 8px 0; font-style: italic; }

/* cron 面板 */
#cron-modal { position: fixed; inset: 0; background: rgba(0,0,0,.5); display: none; align-items: center; justify-content: center; z-index: 60; }
#cron-modal.show { display: flex; }
.cron-card { width: min(680px, 92vw); max-height: 80vh; display: flex; flex-direction: column; }
.cron-row { padding: 10px 12px; border: 1px solid var(--border); border-radius: 6px; background: var(--bg-elev, rgba(255,255,255,0.02)); }
.cron-row-head { display: flex; justify-content: space-between; align-items: center; }
.cron-expr { font-family: ui-monospace, SFMono-Regular, monospace; color: var(--accent); font-size: 13px; font-weight: 600; }
.cron-expr.disabled { color: var(--text-faint); text-decoration: line-through; }
.cron-toggle { font-size: 12px; color: var(--muted, var(--text-dim)); }
.cron-prompt { font-size: 13px; margin: 6px 0; white-space: pre-wrap; word-break: break-word; }
.cron-meta { font-size: 11px; color: var(--muted, var(--text-dim)); }
.cron-edit-card { position: absolute; left: 50%; top: 50%; transform: translate(-50%, -50%); width: min(560px, 88vw); background: var(--bg, #1e1e1e); border: 1px solid var(--border); border-radius: 8px; padding: 16px; box-shadow: 0 8px 32px rgba(0,0,0,.4); display: flex; flex-direction: column; gap: 10px; z-index: 70; }
.cron-edit-card h4 { margin: 0 0 4px; font-size: 14px; }
.cron-edit-card label { display: flex; flex-direction: column; gap: 4px; font-size: 12px; color: var(--text-dim); }
.cron-edit-card input, .cron-edit-card textarea { background: var(--bg-elev, rgba(255,255,255,0.05)); border: 1px solid var(--border); color: var(--text); padding: 6px 8px; border-radius: 4px; font: inherit; }
.cron-edit-actions { display: flex; justify-content: flex-end; gap: 8px; margin-top: 4px; }

/* confirm modal */
#modal, #prompt-modal { position: fixed; inset: 0; background: rgba(0,0,0,.5); display: none; align-items: center; justify-content: center; z-index: 50; }
#modal.show, #prompt-modal.show { display: flex; }
#prompt-input { margin: 10px 0; }
.modal-card { background: var(--bg-elev); border: 1px solid var(--border); border-radius: 10px; padding: 18px; width: 560px; max-width: 90vw; }
.modal-card h3 { margin: 0 0 6px; }
.modal-card pre { background: var(--code-bg); padding: 10px; border-radius: 6px; max-height: 240px; overflow: auto; white-space: pre-wrap; word-break: break-word; font-size: 12px; user-select: text; }
.modal-card .actions { display: flex; justify-content: flex-end; gap: 8px; margin-top: 14px; }

/* quick window */
body.quick { display: flex; flex-direction: column; height: 100vh; padding: 10px; gap: 8px; }
body.quick #q-input { flex: 1; resize: none; }
body.quick #q-out { flex: 1; overflow-y: auto; font-size: 12px; color: var(--text-dim); white-space: pre-wrap; user-select: text; }
body.quick .q-hint { font-size: 11px; color: var(--text-faint); }

/* dashboard window */
body.dash { overflow-y: auto; user-select: none; }
#dash { padding: 20px 24px 48px; max-width: 1000px; margin: 0 auto; }
.dash-head { display: flex; align-items: baseline; gap: 12px; margin-bottom: 18px; }
.dash-head h2 { margin: 0; font-size: 18px; }
.dash-brand { font-size: 12px; color: var(--text-faint); }
#dash h3 { font-size: 12px; color: var(--text-dim); margin: 0 0 10px; font-weight: 600; text-transform: uppercase; letter-spacing: .03em; }
.dash-overview { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-bottom: 26px; }
.dash-card { background: var(--bg-elev); border: 1px solid var(--border); border-radius: 10px; padding: 14px 16px; }
.dc-num { font-size: 22px; font-weight: 700; }
.dc-num.run { color: var(--run); }
.dc-lbl { font-size: 11px; color: var(--text-dim); margin-top: 4px; }
.dash-engines { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; margin-bottom: 28px; }
.dash-eng { background: var(--bg-elev); border: 1px solid var(--border); border-radius: 10px; padding: 12px 14px; }
.de-name { font-size: 13px; font-weight: 600; display: flex; justify-content: space-between; align-items: center; }
.de-count { font-size: 11px; color: var(--text-faint); font-weight: 400; }
.de-bar { height: 6px; background: var(--bg-input); border-radius: 3px; margin: 10px 0 8px; overflow: hidden; }
.de-fill { height: 100%; background: var(--accent); border-radius: 3px; min-width: 2px; }
.de-stats { font-size: 11px; color: var(--text-dim); display: flex; justify-content: space-between; }
.dash-table-wrap { overflow-x: auto; border: 1px solid var(--border); border-radius: 10px; }
.dash-table { width: 100%; border-collapse: collapse; font-size: 12px; }
.dash-table th { text-align: left; color: var(--text-dim); font-weight: 500; padding: 9px 12px; border-bottom: 1px solid var(--border); font-size: 11px; }
.dash-table td { padding: 10px 12px; border-bottom: 1px solid var(--border); }
.dash-table tbody tr:last-child td { border-bottom: none; }
.dash-table tr.run td { background: rgba(232,179,57,.06); }
.dt-name { max-width: 260px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.dt-status { color: var(--text-dim); white-space: nowrap; }
.dt-run { display: inline-block; width: 7px; height: 7px; border-radius: 50%; background: var(--run); margin-right: 6px; vertical-align: 1px; box-shadow: 0 0 6px var(--run); }
.dash-table tr.run .dt-status { color: var(--run); }
.dash-table .mono { font-family: ui-monospace, SFMono-Regular, Menlo, monospace; font-size: 11px; color: var(--text-dim); }
.dt-last { color: var(--text-faint); white-space: nowrap; }
.dash-empty { color: var(--text-faint); padding: 28px; text-align: center; }
@media (max-width: 720px) {
  .dash-overview { grid-template-columns: repeat(2, 1fr); }
  .dash-engines { grid-template-columns: 1fr; }
}

/* streaming turn 的当前动作反馈(三点 + statusNote 文案) */
.typing-note { display: inline-flex; align-items: center; gap: 7px; color: var(--text-dim); font-size: 12.5px; }
.streaming-status { display: flex; align-items: center; gap: 7px; color: var(--text-dim); font-size: 12.5px; margin-top: 4px; }
.streaming-status .typing-text { white-space: pre-wrap; }

/* .files-editor 的 display:flex 盖过 UA 默认 [hidden]{display:none},
   不加这条 editorPane.hidden=true 实际不隐藏 → 空编辑器盖住 webview。 */
.files-editor[hidden] { display: none; }

/* Files & Preview 窗口:左文件树 + 右 webview,上下分头/工具栏 */
body.files { display: flex; flex-direction: column; height: 100vh; margin: 0; user-select: none; }
.files-head { display: flex; align-items: center; gap: 6px; padding: 8px 10px; border-bottom: 1px solid var(--border); background: var(--bg-side); }
.files-cwd { font-size: 12px; color: var(--text-dim); font-family: ui-monospace, SFMono-Regular, Menlo, monospace; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; max-width: 380px; }
.files-spacer { flex: 1; }
.files-addr { flex: 0 1 360px; font: inherit; font-size: 12px; color: var(--text); background: var(--bg-input); border: 1px solid var(--border); border-radius: 6px; padding: 5px 9px; }
.files-body { flex: 1; display: grid; grid-template-columns: 30% 70%; min-height: 0; }
.files-tree { overflow: auto; border-right: 1px solid var(--border); background: var(--bg-side); padding: 4px 0; }
.files-view { min-width: 0; background: #fff; position: relative; }
.files-view webview { width: 100%; height: 100%; display: inline-flex; border: none; }
.files-empty { color: var(--text-faint); font-size: 12px; padding: 14px 16px; }

/* 预览 / 编辑 tab —— 贴在地址栏左边,active 高亮 */
.files-tabs { display: inline-flex; gap: 0; background: var(--bg-input); border: 1px solid var(--border); border-radius: 6px; overflow: hidden; }
.ftab { background: transparent; border: none; color: var(--text-dim); padding: 4px 12px; font-size: 12px; cursor: pointer; border-radius: 0; }
.ftab:hover { color: var(--text); }
.ftab.active { background: var(--accent); color: #1b1b1f; font-weight: 600; }

/* 编辑器铺满 .files-view,文本框 + 底部状态条 */
.files-editor { position: absolute; inset: 0; display: flex; flex-direction: column; background: var(--bg); }
.files-editor > div:first-child { flex: 1; overflow: hidden; min-height: 0; }
.files-editor-bar { display: flex; align-items: center; gap: 8px; padding: 6px 12px; border-top: 1px solid var(--border); background: var(--bg-side); flex-shrink: 0; }
.fe-status { font-size: 11px; color: var(--text-faint); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 60%; }

.fe-row { display: flex; align-items: center; gap: 6px; padding: 3px 10px; cursor: default; font-size: 12.5px; }
.fe-row:hover { background: var(--bg-elev); }
/* 选中态:左竖线 + accent 文字 + elev 底,跟系统文件管理器一致(单击选中、双击打开)。 */
.fe-row.selected { background: var(--bg-elev); color: var(--accent); box-shadow: inset 2px 0 0 var(--accent); }
.fe-row.selected .fe-name { color: var(--accent); }
.fe-ico { width: 14px; text-align: center; flex-shrink: 0; }
.fe-name { color: var(--text); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.fe.file .fe-name { color: var(--text-dim); }
.fe-children .fe-row { padding-left: 24px; }
.fe-children .fe-children .fe-row { padding-left: 38px; }
.fe-children .fe-children .fe-children .fe-row { padding-left: 52px; }
.fe-children .fe-children .fe-children .fe-children .fe-row { padding-left: 66px; }

.files-menu { position: fixed; z-index: 999; background: var(--bg-elev); border: 1px solid var(--border); border-radius: 6px; padding: 4px 0; min-width: 160px; box-shadow: 0 6px 24px rgba(0,0,0,.4); }
.fm-item { padding: 6px 14px; font-size: 12.5px; color: var(--text); cursor: default; }
.fm-item:hover { background: var(--bg-input); }

/* Workbench 视图:头部(标题/副标题 + 新建项目)+ 项目卡片网格。 */
#workbench { padding: 20px 24px 48px; overflow-y: auto; max-width: 1100px; margin: 0 auto; width: 100%; }
.wb-head { display: flex; align-items: baseline; gap: 12px; margin-bottom: 20px; flex-wrap: wrap; }
.wb-head .wb-title { font-size: 18px; font-weight: 700; }
.wb-head .wb-sub { font-size: 12px; color: var(--text-dim); flex: 1 1 320px; line-height: 1.5; }
.wb-spacer { flex: 1; }
.wb-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 14px; }
.wb-card { background: var(--bg-elev); border: 1px solid var(--border); border-radius: 10px; padding: 14px 16px; cursor: pointer; display: flex; flex-direction: column; gap: 6px; transition: border-color .12s; }
.wb-card:hover { border-color: var(--accent-dim); }
.wb-card-head { display: flex; align-items: center; gap: 8px; }
.wb-picon { font-size: 16px; }
.wb-pname { font-weight: 600; font-size: 14px; flex: 1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.wb-cwd { font-size: 11px; color: var(--text-faint); font-family: ui-monospace, SFMono-Regular, Menlo, monospace; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.wb-stats { font-size: 12px; color: var(--text-dim); margin-top: 4px; }
.wb-last { font-size: 11px; color: var(--text-faint); }
.wb-card-actions { display: flex; align-items: center; gap: 6px; margin-top: 4px; }

/* 项目背景编辑器 modal:textarea 占满,头/尾各一行。复用 .modal-card 的基础样式。 */
#context-modal { position: fixed; inset: 0; background: rgba(0,0,0,.5); display: none; align-items: center; justify-content: center; z-index: 50; }
#context-modal.show { display: flex; }
.cm-card { width: 720px; max-width: 92vw; max-height: 80vh; display: flex; flex-direction: column; }
.cm-cwd { font-size: 11px; color: var(--text-faint); font-family: ui-monospace, SFMono-Regular, Menlo, monospace; margin: 2px 0 10px; word-break: break-all; }
.cm-editor-host { flex: 1; min-height: 320px; overflow: hidden; }
.cm-card .actions { display: flex; align-items: center; gap: 8px; margin-top: 10px; }
.cm-status { font-size: 12px; color: var(--text-dim); }
.cm-spacer { flex: 1; }

/* 长期记忆面板(🧠)+ 快照面板(⏪):modal 形态,头(scope 切换 + 关闭)+ 列表。 */
#memory-modal, #snapshot-modal { position: fixed; inset: 0; background: rgba(0,0,0,.5); display: none; align-items: center; justify-content: center; z-index: 50; }
#memory-modal.show, #snapshot-modal.show { display: flex; }
.mm-card { width: 720px; max-width: 92vw; max-height: 80vh; display: flex; flex-direction: column; }
.mm-head { display: flex; align-items: center; gap: 10px; }
.mm-head h3 { margin: 0; flex: 0 0 auto; }
.mm-scope { display: flex; gap: 4px; flex: 1; }
.mm-view { display: flex; gap: 4px; flex: 0 0 auto; }
.mm-view button { padding: 4px 10px; font-size: 12px; }
.mm-view button.active { background: var(--accent); color: var(--bg-elev); border-color: var(--accent); }
.mm-scope button { padding: 4px 10px; font-size: 12px; }
.mm-scope button.active { background: var(--accent); color: var(--bg-elev); border-color: var(--accent); }
#mm-close { padding: 4px 10px; font-size: 18px; line-height: 1; }
.mm-list { flex: 1; overflow-y: auto; margin-top: 12px; display: flex; flex-direction: column; gap: 8px; min-height: 0; }
/* graph viz 模式:mm-list 撑满可用空间给 canvas */
.mm-list:has(.mm-graph-wrap) { flex: 1 1 400px; overflow: hidden; }
.mm-empty { color: var(--text-dim); font-size: 13px; padding: 24px; text-align: center; }
.mm-row { border: 1px solid var(--border); border-radius: 8px; padding: 10px 12px; display: flex; flex-direction: column; gap: 6px; background: var(--bg); }
.mm-text { font-size: 13px; line-height: 1.5; user-select: text; white-space: pre-wrap; word-break: break-word; }
.mm-from { font-size: 11px; color: var(--text-faint); }
.mm-actions { display: flex; gap: 6px; justify-content: flex-end; }
.mm-actions button { padding: 3px 10px; font-size: 12px; }
.mm-input { width: 100%; min-height: 60px; resize: vertical; font: inherit; font-size: 13px; padding: 8px; user-select: text; }

/* Memory Graph 三元组行:[s] → predicate → [o] */
.mm-triple-line { display: flex; flex-wrap: wrap; align-items: center; gap: 8px; font-size: 13px; user-select: text; }
.mm-triple-node { padding: 2px 8px; background: var(--bg-elev); border: 1px solid var(--border); border-radius: 4px; }
.mm-triple-arrow { color: var(--accent); font-size: 12px; }

/* Memory Graph 力导向图可视化 / Force-directed graph visualization */
.mm-graph-wrap { position: relative; width: 100%; height: 100%; min-height: 360px; overflow: hidden; border-radius: 8px; background: #161619; }
.mm-graph-canvas { display: block; width: 100%; height: 100%; cursor: default; }
.mm-graph-tip { position: absolute; bottom: 8px; left: 12px; font-size: 11px; color: var(--text-faint); pointer-events: none; background: rgba(22,22,25,0.7); padding: 3px 8px; border-radius: 4px; }
#mm-graph-viz { font-size: 15px; padding: 2px 8px; }

/* Arena 窗口(⚔):同一 prompt 三引擎并跑,三栏并排。 */
body.arena { display: flex; flex-direction: column; height: 100vh; margin: 0; background: var(--bg); color: var(--text); font: 13px system-ui, -apple-system, "Segoe UI", Roboto, sans-serif; }
.arena-head { display: flex; align-items: center; gap: 8px; padding: 10px 14px; border-bottom: 1px solid var(--border); background: var(--bg-elev); }
.arena-cwd { font-size: 12px; color: var(--text-dim); flex: 0 1 auto; max-width: 32%; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.arena-input { flex: 1; font: inherit; padding: 6px 10px; background: var(--bg); color: var(--text); border: 1px solid var(--border); border-radius: 6px; }
.arena-input:focus { outline: none; border-color: var(--accent); }
#arena-run { flex: 0 0 auto; }
.arena-cols { flex: 1; display: grid; grid-template-columns: repeat(3, 1fr); gap: 1px; background: var(--border); overflow: hidden; }
.arena-col { display: flex; flex-direction: column; background: var(--bg); overflow: hidden; }
.arena-col-head { display: flex; justify-content: space-between; align-items: center; padding: 8px 12px; font-size: 12px; border-bottom: 1px solid var(--border); background: var(--bg-elev); }
.arena-col-engine { font-weight: 600; }
.arena-col-status { color: var(--text-faint); font-size: 11px; }
.arena-col-status.running { color: var(--accent); }
.arena-col-status.done { color: #4ade80; }
.arena-col-status.error { color: #f87171; }
.arena-col-body { flex: 1; overflow-y: auto; padding: 12px; }
.arena-answer { margin: 0; white-space: pre-wrap; word-break: break-word; font: inherit; color: var(--text); user-select: text; }
.arena-idle, .arena-waiting { color: var(--text-faint); font-style: italic; }
.arena-err { color: #f87171; white-space: pre-wrap; user-select: text; }
.arena-col-foot { padding: 4px 12px; font-size: 11px; color: var(--text-faint); border-top: 1px solid var(--border); background: var(--bg-elev); }

/* ── Pipeline 编排 ── */
#pipeline-root, #templates-root, #cost-root { padding: 20px; overflow-y: auto; height: 100%; }
.pl-head, .tpl-head, .cost-head { margin-bottom: 20px; }
.pl-title, .tpl-title, .cost-title { font-size: 18px; font-weight: 700; }
.pl-sub, .tpl-sub, .cost-sub { color: var(--text-dim); font-size: 12px; margin-top: 4px; }
.pl-editor { background: var(--bg-elev); border-radius: 10px; padding: 16px; margin-bottom: 20px; }
.pl-field { margin-bottom: 12px; }
.pl-field label { display: block; font-size: 12px; color: var(--text-dim); margin-bottom: 4px; }
.pl-field .row { display: flex; gap: 6px; }
.pl-field .row input { flex: 1; }
.pl-stages-label { font-size: 13px; font-weight: 600; color: var(--text); margin: 12px 0 8px; }
.pl-stage { background: var(--bg-input); border: 1px solid var(--border); border-radius: 8px; padding: 10px; margin-bottom: 8px; }
.pl-stage-head { display: flex; gap: 6px; align-items: center; margin-bottom: 6px; }
.pl-stage-label { width: 120px; flex: 0 0 120px; }
.pl-stage-engine { width: 160px; flex: 0 0 160px; }
.pl-stage-del { padding: 4px 8px; }
.pl-stage-prompt { resize: vertical; min-height: 60px; }
.pl-add-stage { margin: 8px 0; }
.pl-actions { display: flex; gap: 8px; align-items: center; margin-top: 12px; }
.pl-templates h3 { font-size: 14px; margin: 0 0 10px; }
.pl-saved-item { background: var(--bg-input); border: 1px solid var(--border); border-radius: 8px; padding: 10px; margin-bottom: 6px; }
.pl-saved-name { font-weight: 600; }
.pl-saved-meta { font-size: 11px; color: var(--text-dim); margin: 2px 0 6px; }
.pl-saved-actions { display: flex; gap: 6px; }
.pl-empty { color: var(--text-faint); font-style: italic; }
.pl-loading { color: var(--text-dim); padding: 20px; }

/* ── 模板库 ── */
.tpl-body { display: flex; flex-direction: column; gap: 20px; }
.tpl-cat h3 { font-size: 14px; margin: 0 0 10px; color: var(--text-dim); }
.tpl-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(240px, 1fr)); gap: 12px; }
.tpl-card { background: var(--bg-elev); border: 1px solid var(--border); border-radius: 10px; padding: 14px; display: flex; flex-direction: column; gap: 4px; }
.tpl-card:hover { border-color: var(--accent-dim); }
.tpl-card-icon { font-size: 24px; }
.tpl-card-name { font-weight: 600; font-size: 14px; }
.tpl-card-desc { font-size: 11px; color: var(--text-dim); flex: 1; }
.tpl-card-engine { font-size: 10px; color: var(--accent); font-family: ui-monospace, monospace; }
.tpl-card-actions { display: flex; gap: 6px; margin-top: 6px; }

/* ── 成本看板 ── */
.cost-overview { display: flex; gap: 12px; margin-bottom: 20px; }
.cost-card { background: var(--bg-elev); border: 1px solid var(--border); border-radius: 10px; padding: 16px; flex: 1; text-align: center; }
.cc-num { font-size: 22px; font-weight: 700; color: var(--accent); }
.cc-lbl { font-size: 11px; color: var(--text-dim); margin-top: 4px; }
.cost-chart-section { margin-bottom: 20px; }
.cost-chart-section h3, .cost-engine-section h3, .cost-budget-section h3 { font-size: 14px; margin: 0 0 10px; }
#cost-canvas { width: 100%; border-radius: 8px; border: 1px solid var(--border); }
.cost-engines { display: flex; flex-direction: column; gap: 8px; }
.cost-eng { display: flex; align-items: center; gap: 10px; }
.ce-name { width: 140px; font-size: 12px; }
.ce-bar { flex: 1; height: 20px; background: var(--bg-input); border-radius: 4px; overflow: hidden; }
.ce-fill { height: 100%; background: var(--accent); border-radius: 4px; transition: width .3s; }
.ce-val { width: 80px; text-align: right; font-size: 12px; color: var(--text-dim); font-family: ui-monospace, monospace; }
.cost-empty { color: var(--text-faint); font-style: italic; padding: 12px; }
.cost-budget-section { margin-top: 20px; }
.cost-budget-form { background: var(--bg-elev); border-radius: 10px; padding: 16px; }
.cost-budget-form .field { margin-bottom: 10px; }
.cost-loading { color: var(--text-dim); padding: 20px; }

/* ── 规则生成器 modal ── */
.modal-overlay { position: fixed; inset: 0; background: rgba(0,0,0,.5); display: flex; align-items: center; justify-content: center; z-index: 9999; }
.rg-body { max-height: 60vh; overflow-y: auto; }
.rg-body .field { margin-bottom: 10px; }
.rg-body label { display: block; font-size: 12px; color: var(--text-dim); margin-bottom: 4px; }

/* ── 图片附件 chips ── */
.img-chip { position: relative; padding: 2px; display: inline-flex; align-items: center; }
.img-chip img { width: 40px; height: 40px; object-fit: cover; border-radius: 4px; pointer-events: none; }
.img-chip .chip-x { position: absolute; top: -4px; right: -4px; background: var(--err); color: #fff; border-radius: 50%; width: 16px; height: 16px; display: flex; align-items: center; justify-content: center; font-size: 11px; line-height: 1; }

/* ── 自定义工具视图 ── */
.ctool-card { border: 1px solid var(--border); border-radius: 8px; padding: 12px; margin-bottom: 8px; background: var(--bg-elev); }
.ctool-head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 4px; }
.ctool-desc { font-size: 12px; color: var(--text-dim); margin-bottom: 4px; }
.ctool-cmd { font-size: 11px; }
.ctool-cmd code { background: var(--code-bg); padding: 2px 6px; border-radius: 4px; font-family: ui-monospace, monospace; color: var(--accent); }
.ctool-actions { display: flex; gap: 4px; }
button.sm { padding: 3px 8px; font-size: 11px; }

/* ── 记忆时间线 ── */
.mem-tl-item { position: relative; border-left: 3px solid var(--border); margin-bottom: 6px; padding: 0 0 0 12px; }
.mem-tl-bar { position: absolute; left: -3px; top: 0; bottom: 0; width: 3px; border-radius: 2px; }
.mem-tl-content { display: flex; flex-direction: column; gap: 2px; padding: 6px 0; }
.mem-tl-date { font-size: 11px; color: var(--text-faint); }
.mem-tl-text { font-size: 12px; }
.mem-tl-meta { font-size: 11px; color: var(--text-faint); }

/* ── 回放模态框 ── */
.replay-header { display: flex; justify-content: space-between; align-items: center; }
.replay-header h3 { margin: 0; }
.replay-progress { display: flex; gap: 4px; margin: 12px 0; }
.replay-dot { flex: 1; height: 4px; border-radius: 2px; background: var(--border); transition: background .2s; }
.replay-dot.done { background: var(--ok); }
.replay-dot.active { background: var(--accent); }
.replay-body { max-height: 50vh; overflow-y: auto; }
.replay-tool { font-weight: 600; color: var(--accent); margin-bottom: 6px; }
.replay-dur { font-size: 11px; color: var(--text-faint); }
.replay-section { margin-bottom: 10px; }
.replay-label { font-size: 11px; color: var(--text-dim); margin-bottom: 3px; }
.replay-args, .replay-result { background: var(--code-bg); padding: 8px; border-radius: 4px; font-family: ui-monospace, monospace; font-size: 11px; white-space: pre-wrap; word-break: break-word; max-height: 200px; overflow-y: auto; user-select: text; }
.replay-controls { display: flex; gap: 6px; justify-content: center; margin-top: 14px; }

/* ── Arena Diff ── */
.arena-toolbar { padding: 8px 16px; text-align: center; }
.arena-diff-panel { padding: 12px 16px; border-top: 1px solid var(--border); max-height: 40vh; overflow-y: auto; }
.arena-diff-head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px; }
.arena-diff-head h3 { margin: 0; font-size: 14px; }
.arena-diff-body { font-family: ui-monospace, monospace; font-size: 12px; white-space: pre-wrap; word-break: break-word; user-select: text; }
.arena-diff-body .d-add { color: var(--ok); display: block; }
.arena-diff-body .d-del { color: var(--err); display: block; }

/* ── 导出/回放按钮(turn 工具栏) ── */
.ai-branch, .ai-replay, .ai-export { font-size: 13px; padding: 2px 6px; }

/* ── 视图通用 ── */
.empty-hint { color: var(--text-faint); font-size: 13px; padding: 20px 0; text-align: center; }
.settings-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
.settings-grid .field { margin-bottom: 8px; }
.settings-grid label { display: block; font-size: 12px; color: var(--text-dim); margin-bottom: 3px; }

/* ════════════════════════════════════════════════════════════════════════════
   CodeEditor:自研轻量代码编辑器 / Lightweight code editor component
   双层叠加:底 pre(高亮) + 上 textarea(透明文字),行号槽在左。
   ════════════════════════════════════════════════════════════════════════════ */

/* 宿主容器 / Host container */
.ce-host { display: block; position: relative; }

/* 全屏模式:撑满父容器 */
.ce-wrap.ce-full {
  display: flex;
  height: 100%;
  overflow: hidden;
  background: var(--code-bg);
  border-radius: 6px;
}

/* 行号槽 / Line number gutter */
.ce-gutter {
  flex-shrink: 0;
  padding: 12px 0;
  text-align: right;
  user-select: none;
  pointer-events: none;
  overflow: hidden;
  background: rgba(0,0,0,.18);
  border-right: 1px solid var(--border);
  min-width: 40px;
}
.ce-ln {
  font: 12px/1.65 "JetBrains Mono", "Cascadia Code", Consolas, monospace;
  color: var(--text-faint);
  padding: 0 10px;
  height: calc(1.65 * 13px);
}

/* 滚动区 / Scroll area */
.ce-scroll {
  position: relative;
  flex: 1;
  overflow: hidden;
}

/* 高亮层 / Highlight layer */
.ce-highlight {
  position: absolute;
  inset: 0;
  margin: 0;
  padding: 12px 16px;
  font: 13px/1.65 "JetBrains Mono", "Cascadia Code", Consolas, "PingFang SC", monospace;
  white-space: pre;
  overflow: auto;
  pointer-events: none;
  color: var(--text);
  background: transparent;
  word-break: normal;
  tab-size: 2;
}

/* 透明输入层 / Transparent input layer */
.ce-input {
  position: absolute;
  inset: 0;
  margin: 0;
  padding: 12px 16px;
  font: 13px/1.65 "JetBrains Mono", "Cascadia Code", Consolas, "PingFang SC", monospace;
  white-space: pre;
  background: transparent;
  color: transparent;
  caret-color: var(--accent);
  border: none;
  outline: none;
  resize: none;
  overflow: auto;
  tab-size: 2;
  width: 100%;
  height: 100%;
}
.ce-input::placeholder {
  color: var(--text-faint);
  opacity: 0.6;
}
/* 滚动条美化 / Custom scrollbar */
.ce-input::-webkit-scrollbar,
.ce-highlight::-webkit-scrollbar { width: 8px; height: 8px; }
.ce-input::-webkit-scrollbar-thumb,
.ce-highlight::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 4px;
}
.ce-input::-webkit-scrollbar-thumb:hover,
.ce-highlight::-webkit-scrollbar-thumb:hover {
  background: var(--text-faint);
}

/* ── autoHeight 模式(内联编辑器) ── */
.ce-wrap.ce-auto {
  position: relative;
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 6px;
  overflow: hidden;
  min-height: calc(var(--ce-lines, 3) * calc(13px * 1.65) + 24px);
  transition: border-color .15s;
}
.ce-wrap.ce-auto: focus-within {
  border-color: var(--accent);
  box-shadow: 0 0 0 1px var(--accent-dim);
}
.ce-wrap.ce-auto .ce-scroll {
  overflow: visible;
}
.ce-wrap.ce-auto .ce-highlight {
  position: relative;
  overflow: visible;
}
.ce-wrap.ce-auto .ce-input {
  position: absolute;
  height: 100%;
  overflow: hidden;
}

/* ═══ Token 颜色 / Token colors ═══════════════════════════════════════════════ */
/* 深色主题:参考 VS Code Dark+ 微调，与品牌色协调 */
.tok-keyword   { color: #c586c0; }          /* 紫粉 */
.tok-string    { color: #ce9178; }          /* 橙棕 */
.tok-comment   { color: #6a9955; font-style: italic; } /* 绿 */
.tok-number    { color: #b5cea8; }          /* 浅绿 */
.tok-function  { color: #dcdcaa; }          /* 黄 */
.tok-builtin   { color: #4ec9b0; }          /* 青绿 */
.tok-decorator { color: #dcdcaa; }          /* 黄 */
.tok-tag       { color: #569cd6; }          /* 蓝 */
.tok-attr      { color: #9cdcfe; }          /* 浅蓝 */
.tok-variable  { color: #9cdcfe; }          /* 浅蓝 */
.tok-property  { color: #9cdcfe; }          /* 浅蓝 */
.tok-selector  { color: #d7ba7d; }          /* 金棕 */
.tok-atrule    { color: #c586c0; }          /* 紫粉 */
.tok-header    { color: #569cd6; font-weight: 700; }
.tok-list      { color: #6a9955; }
.tok-codeblock { color: #ce9178; background: rgba(255,255,255,.03); display: block; }
.tok-inlinecode{ color: #ce9178; background: rgba(255,255,255,.05); padding: 0 3px; border-radius: 3px; }
.tok-bold      { color: var(--text); font-weight: 700; }
.tok-italic    { color: var(--text-dim); font-style: italic; }
.tok-link      { color: #3794ff; text-decoration: underline; }
.tok-key       { color: #9cdcfe; }          /* JSON/YAML key */

/* ── 淡色主题 / Light theme tokens ── */
[data-theme="light"] .tok-keyword   { color: #af00db; }
[data-theme="light"] .tok-string    { color: #a31515; }
[data-theme="light"] .tok-comment   { color: #008000; }
[data-theme="light"] .tok-number    { color: #098658; }
[data-theme="light"] .tok-function  { color: #795e26; }
[data-theme="light"] .tok-builtin   { color: #267f99; }
[data-theme="light"] .tok-decorator { color: #795e26; }
[data-theme="light"] .tok-tag       { color: #800000; }
[data-theme="light"] .tok-attr      { color: #ff0000; }
[data-theme="light"] .tok-variable  { color: #001080; }
[data-theme="light"] .tok-property  { color: #001080; }
[data-theme="light"] .tok-selector  { color: #800000; }
[data-theme="light"] .tok-atrule    { color: #af00db; }
[data-theme="light"] .tok-header    { color: #0000ff; }
[data-theme="light"] .tok-codeblock { color: #a31515; }
[data-theme="light"] .tok-inlinecode{ color: #a31515; }
[data-theme="light"] .tok-key       { color: #0451a5; }
[data-theme="light"] .tok-link      { color: #0000ee; }
